import { cn } from "@/lib/utils";
import type { HTMLAttributes, HTMLTag } from "astro/types";

interface Props extends HTMLAttributes<"div"> {
  as?: HTMLTag;
  class?: string;
}

const {
  as: Tag = "div",
  class: className = "",
  ...rest
} = Astro.props as Props;
---

<Tag
  {...rest}
  data-slot="avatar-group-count"
  class={cn(
    "bg-muted text-muted-foreground size-8 rounded-full text-xs/relaxed group-has-data-[size=lg]/avatar-group:size-10 group-has-data-[size=sm]/avatar-group:size-6 [&>svg]:size-4 group-has-data-[size=lg]/avatar-group:[&>svg]:size-5 group-has-data-[size=sm]/avatar-group:[&>svg]:size-3",
    "bg-muted text-muted-foreground ring-background relative flex size-8 shrink-0 items-center justify-center rounded-full text-sm ring-2",
    "[&>svg]:size-4",
    "group-has-data-[size=sm]/avatar-group:size-6 group-has-data-[size=sm]/avatar-group:[&>svg]:size-3",
    "group-has-data-[size=lg]/avatar-group:size-10 group-has-data-[size=lg]/avatar-group:[&>svg]:size-5",
    className,
  )}
>
  <slot />
</Tag>

---
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"img"> {
  class?: string;
  src?: string;
  alt?: string;
}

const {
  class: className = "",
  src,
  alt = "",
  ...rest
} = Astro.props as Props;
---

{
  src ? (
    <img
      {...rest}
      data-slot="avatar-image"
      src={src}
      alt={alt}
      class={cn(
        "rounded-full",
        "relative z-10 aspect-square size-full object-cover",
        className,
      )}
    />
  ) : (
    <div
      {...rest}
      data-slot="avatar-image"
      class={cn(
        "rounded-full",
        "relative z-10 aspect-square size-full overflow-hidden",
        "[&_img]:size-full [&_img]:object-cover",
        className,
      )}
    >
      <slot />
    </div>
  )
}

export { default as Avatar } from "./Avatar.astro";
export { default as AvatarImage } from "./AvatarImage.astro";
export { default as AvatarFallback } from "./AvatarFallback.astro";
export { default as AvatarBadge } from "./AvatarBadge.astro";
export { default as AvatarGroup } from "./AvatarGroup.astro";
export { default as AvatarGroupCount } from "./AvatarGroupCount.astro";
